// E03S06 — AC2, AC3: Build canonical En Route customer SMS
// Template: '[Business Name]: Your technician is on the way.'
// AC3: business_name ALWAYS from clients table — never hardcoded

const businessName = $('GET Client Details').item.json.business_name;
const customerPhone = $('Split In Items').item.json.customer_phone;
const twilioFromNumber = $('GET Client Details').item.json.twilio_number;

// Validate required fields — fail loudly, not silently
if (!businessName) throw new Error('[E03S06] Missing clients.business_name — cannot build En Route SMS');
if (!customerPhone) throw new Error('[E03S06] customer_phone missing — should not reach Build SMS Body (check IF node wiring)');

// AC2: Exact template from conventions.md
// '[Business Name]: Your technician is on the way.'
const smsBody = businessName + ': Your technician is on the way.';

return [{
  json: {
    smsBody: smsBody,
    customerPhone: customerPhone,
    twilioFromNumber: twilioFromNumber
  }
}];
